import{_ as a,o as d,c as t,a2 as o}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Configuración","description":"","frontmatter":{},"headers":[],"relativePath":"es/guide/configuration.md","filePath":"es/guide/configuration.md"}'),s={name:"es/guide/configuration.md"};function i(n,e,c,r,l,p){return d(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="configuracion" tabindex="-1">Configuración <a class="header-anchor" href="#configuracion" aria-label="Permalink to &quot;Configuración&quot;">​</a></h1><p>Clearance viene con valores predeterminados sensatos, así que funciona de inmediato tras la <a href="/clearance-docs/es/guide/installation.html">instalación</a>. Publica el archivo de configuración cuando necesites personalizar el prefijo de ruta, el middleware, los modelos contextuales, o cualquier otro ajuste.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Esto publica <code>config/clearance.php</code>.</p><h2 id="referencia-de-configuracion" tabindex="-1">Referencia de configuración <a class="header-anchor" href="#referencia-de-configuracion" aria-label="Permalink to &quot;Referencia de configuración&quot;">​</a></h2><p>Esta es la referencia definitiva de cada clave en <code>config/clearance.php</code>. El resto de páginas de esta documentación enlazan aquí en lugar de repetir la tabla.</p><table tabindex="0"><thead><tr><th>Clave</th><th>Predeterminado</th><th>Propósito</th></tr></thead><tbody><tr><td><code>route_prefix</code></td><td><code>&#39;clearance&#39;</code></td><td>Prefijo de URI para todas las rutas del panel.</td></tr><tr><td><code>middleware</code></td><td><code>[&#39;web&#39;, &#39;auth&#39;]</code></td><td>Se aplica a todas las rutas del panel antes de <code>clearance.access</code>.</td></tr><tr><td><code>access_permission</code></td><td><code>&#39;clearance-access&#39;</code></td><td>Permiso verificado por el middleware de acceso.</td></tr><tr><td><code>user_model</code></td><td><code>null</code></td><td>Por defecto usa <code>auth.providers.users.model</code>.</td></tr><tr><td><code>modules.users</code></td><td><code>false</code></td><td>Interruptor maestro para el módulo de Usuarios (rutas + componentes Livewire).</td></tr><tr><td><code>contextual_models</code></td><td><code>[]</code></td><td><code>FQCN =&gt; [&#39;label&#39;, &#39;icon&#39;, &#39;label_attribute&#39;, &#39;searchable&#39;]</code> - modelos que pueden actuar como contextos de vinculación de rol.</td></tr><tr><td><code>enforce_naming_convention</code></td><td><code>true</code></td><td>Fuerza la convención de nomenclatura <code>group-action</code>.</td></tr><tr><td><code>naming_separator</code></td><td><code>&#39;-&#39;</code></td><td>Carácter separador - solo <code>&#39;-&#39;</code> o <code>&#39;_&#39;</code>.</td></tr><tr><td><code>guards</code></td><td><code>[]</code></td><td>Sobrescribe los guards auto-detectados desde <code>config/auth.php</code>. Vacío = auto-detecta todos.</td></tr><tr><td><code>allowed_guard_drivers</code></td><td><code>[&#39;session&#39;, &#39;token&#39;, &#39;jwt&#39;, &#39;passport&#39;, &#39;sanctum&#39;]</code></td><td>Drivers aceptados al inyectar guards de BD en <code>auth.guards</code>.</td></tr><tr><td><code>layout</code></td><td><code>null</code></td><td>Layout Blade para componentes de página completa. <code>null</code> = predeterminado de la app anfitriona (<code>config(&#39;livewire.layout&#39;)</code>).</td></tr><tr><td><code>auto_assign_default_role</code></td><td><code>false</code></td><td>Auto-asigna el rol predeterminado configurado en Configuración al evento <code>Registered</code>.</td></tr><tr><td><code>super_admin_gate_bypass</code></td><td><code>false</code></td><td>Opcional: <code>super_admin</code> evita todas las comprobaciones de Gate en toda la aplicación.</td></tr><tr><td><code>ui.flux_pro</code></td><td><code>null</code></td><td><code>null</code> = auto-detecta vía <code>Flux::pro()</code>.</td></tr></tbody></table><h2 id="convencion-de-nomenclatura-de-permisos" tabindex="-1">Convención de nomenclatura de permisos <a class="header-anchor" href="#convencion-de-nomenclatura-de-permisos" aria-label="Permalink to &quot;Convención de nomenclatura de permisos&quot;">​</a></h2><p>Los permisos deben seguir el formato <code>group-action</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Desactiva la validación por entorno con <code>enforce_naming_convention</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">El separador se valida al arrancar</p><p>El valor <code>naming_separator</code> es la única parte de esta configuración que llega a un fragmento SQL sin procesar (agrupación/ordenación de permisos), así que solo se aceptan <code>-</code> o <code>_</code>.</p></div><h2 id="personalizar-el-middleware" tabindex="-1">Personalizar el middleware <a class="header-anchor" href="#personalizar-el-middleware" aria-label="Permalink to &quot;Personalizar el middleware&quot;">​</a></h2><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;middleware&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;web&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;auth&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;verified&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span></code></pre></div><p>Los nombres de ruta permanecen estables sin importar los cambios de prefijo o middleware - consulta el <a href="/clearance-docs/es/guide/quick-start.html">Inicio Rápido</a> para la tabla completa de rutas.</p><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/es/guide/quick-start.html">Inicio Rápido</a> - montar el panel con esta configuración aplicada</li><li><a href="/clearance-docs/es/guide/publishing.html">Publicación de assets</a> - publicar traducciones y entender la clave <code>layout</code></li><li><a href="/clearance-docs/es/features/guards.html">Guards</a> - cómo se usan <code>guards</code> y <code>allowed_guard_drivers</code></li><li><a href="/clearance-docs/es/features/super-admin.html">Super Admin</a> - cómo funciona <code>super_admin_gate_bypass</code></li></ul>`,18)])])}const g=a(s,[["render",i]]);export{h as __pageData,g as default};
